boolean validateWrite()
{
    boolean ret;

    ret = next validateWrite();

    InventTable     inventTable = this.cursor();

    if(inventTable.ETGSFGMapping)
    {
        this.object(fieldNum(InventTable, ETG_SFGQuantity)).mandatory(true);
        this.object(fieldNum(InventTable, ETGPackagingMaterial)).mandatory(true);
    }
    else
    {
        this.object(fieldNum(InventTable, ETG_SFGQuantity)).mandatory(false);
        this.object(fieldNum(InventTable, ETGPackagingMaterial)).mandatory(false);
    }

    return ret;
}
